{
  "grammar": [
    {
      "pattern": "請 + 幫我 + verb + object",
      "structure": ["請", "幫我", "verb", "object"],
      "explanation_en": "Use this pattern to politely ask someone to do something for you. It is commonly used when requesting help from a landlord or repair person.",
      "title": "Polite Requests with 請幫我",
      "meaning": "Please help me do something",
      "when_to_use": ["When asking a landlord to fix something", "When requesting a repair person to check an issue", "When needing assistance with a household problem"],
      "when_not_to_use": ["When giving a direct command without politeness", "When the action is for yourself only"],
      "pragmatic_notes": "In Taiwan, using 請幫我 is very polite and shows respect. It is common to add 麻煩你 for extra politeness in formal situations.",
      "word_order_notes": "The verb must come after 幫我, and the object after the verb. Do not place the object before 幫我.",
      "english_contrast": "In English, you might say 'Please help me fix the toilet.' In Chinese, the structure is fixed: 請幫我 + verb + object.",
      "korean_contrast": "In Korean, you might say '도와주세요' (please help me). In Chinese, 請幫我 is similar but requires a specific verb after 幫我.",
      "negative_examples": [
        {
          "text": "請幫我馬桶修理。",
          "error": "The verb 修理 should come after 幫我, not after the object."
        }
      ],
      "incorrect_examples": [
        {
          "text": "請修理幫我馬桶。",
          "error": "The word order is wrong: 修理 should be after 幫我, not before."
        }
      ],
      "transformation_drills": ["Change '請幫我修理馬桶' to '請幫我檢查水龍頭'", "Change '請幫我換燈泡' to '請幫我看看問題'"],
      "production_drills": ["Ask the landlord to fix the door lock", "Ask the repair person to check the air conditioner"],
      "common_error_patterns": ["Placing the verb before 幫我", "Omitting 幫我 and using a direct command"],
      "repair_feedback": {
        "word_order": "Remember: 請幫我 + verb + object. The verb must come after 幫我.",
        "politeness": "Using 請幫我 is polite. For extra politeness, add 麻煩你 at the end.",
        "vocabulary": "Use specific verbs like 修理, 檢查, 換 for repair situations."
      }
    },
    {
      "pattern": "什麼時候 + 可以 + verb",
      "structure": ["什麼時候", "可以", "verb"],
      "explanation_en": "Use this pattern to ask when something can be done. It is useful for scheduling repairs or visits with a landlord or repair person.",
      "title": "Asking About Time with 什麼時候可以",
      "meaning": "When can (someone) do something?",
      "when_to_use": ["When asking when a repair person can come", "When asking when the landlord can check something", "When scheduling a visit"],
      "when_not_to_use": ["When asking about past events", "When the subject is not clear from context"],
      "pragmatic_notes": "In Taiwan, this is a polite way to ask about availability. You can add 你 or 您 for clarity, but it is often omitted if the context is clear.",
      "word_order_notes": "什麼時候 comes first, followed by 可以 and then the verb. Do not place the verb before 可以.",
      "english_contrast": "In English, you might say 'When can you come?' In Chinese, the structure is '什麼時候可以 + verb'.",
      "korean_contrast": "In Korean, you might say '언제 올 수 있어요?' (When can you come?). In Chinese, the structure is similar but uses 可以 instead of a separate verb for ability.",
      "negative_examples": [
        {
          "text": "可以什麼時候來？",
          "error": "什麼時候 should come before 可以, not after."
        }
      ],
      "incorrect_examples": [
        {
          "text": "什麼時候來可以？",
          "error": "可以 should come before the verb 來, not after."
        }
      ],
      "transformation_drills": ["Change '什麼時候可以來？' to '什麼時候可以修理？'", "Change '什麼時候可以檢查？' to '什麼時候可以換？'"],
      "production_drills": ["Ask when the repair person can come", "Ask when the landlord can check the water heater"],
      "common_error_patterns": ["Placing 可以 before 什麼時候", "Omitting 可以 and using a direct question"],
      "repair_feedback": {
        "word_order": "Remember: 什麼時候 + 可以 + verb. 什麼時候 always comes first.",
        "politeness": "This pattern is polite. For extra politeness, add 請問 at the beginning.",
        "vocabulary": "Use verbs like 來, 修理, 檢查 for repair situations."
      }
    },
    {
      "pattern": "可能 + 是 + problem + 的 + 問題",
      "structure": ["可能", "是", "problem", "的", "問題"],
      "explanation_en": "Use this pattern to suggest a possible cause of a problem. It is useful when describing issues to a landlord or repair person.",
      "title": "Expressing Possible Causes with 可能是...的問題",
      "meaning": "It might be a problem with...",
      "when_to_use": ["When guessing the cause of a leak", "When suggesting what might be broken", "When describing a strange sound or smell"],
      "when_not_to_use": ["When you are certain about the cause", "When the problem is not related to a specific part"],
      "pragmatic_notes": "In Taiwan, this pattern is used to politely suggest a cause without being too assertive. It shows you are open to the repair person's opinion.",
      "word_order_notes": "可能 is followed by 是, then the specific problem, then 的, and finally 問題. Do not omit 的.",
      "english_contrast": "In English, you might say 'It might be a problem with the toilet.' In Chinese, the structure is '可能是 + problem + 的 + 問題'.",
      "korean_contrast": "In Korean, you might say '변기 문제일 수도 있어요' (It might be a toilet problem). In Chinese, the structure uses 可能 and 的 to connect the problem.",
      "negative_examples": [
        {
          "text": "可能是馬桶問題。",
          "error": "The 的 is missing. It should be '馬桶的問題'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "是可能馬桶的問題。",
          "error": "可能 should come before 是, not after."
        }
      ],
      "transformation_drills": ["Change '可能是馬桶的問題' to '可能是水龍頭的問題'", "Change '可能是冷氣的問題' to '可能是熱水器的問題'"],
      "production_drills": ["Suggest the problem might be with the door lock", "Suggest the problem might be with the air conditioner"],
      "common_error_patterns": ["Omitting 的 between the problem and 問題", "Placing 是 before 可能"],
      "repair_feedback": {
        "word_order": "Remember: 可能 + 是 + problem + 的 + 問題. 可能 always comes first.",
        "politeness": "This pattern is polite and tentative. It shows you are not accusing anyone.",
        "vocabulary": "Use specific nouns like 馬桶, 水龍頭, 冷氣 for the problem."
      }
    }
  ]
}
